```c
#include <stdio.h>
#include <stdint.h>
#include <inttypes.h>
#include <time.h>
#include <stdlib.h>

//常量
#define ROCK 1
#define PAPER 2
#define SCISSORS 3
//全局变量
uint32_t input;
uint32_t robot_input;

//函数声明
void print_rule();
int get_input_move();
int get_robot_move();
void determine_winner(input, robot_input);

//石头剪刀布与软件工程的[规则映射]设计技巧
int main(){
	//初始化随机数生成器
	srand(time(NULL));
	print_rule();
	input = get_input_move();
	while (input == 0) {
		printf("\n");
		input = get_input_move();
	}
	robot_input = get_robot_move();
	printf("你选择了%" PRIu32 "\n", input);
	printf("机器人选择了%" PRIu32 "\n", robot_input);
	determine_winner(input, robot_input);
	return 0;
}

void print_rule() {
	printf("石头剪刀布游戏规则:\n");
	printf("1：石头，2：布，3：剪刀\n");
}

int get_input_move() {
