	scanf_s("%" SCNu32, &input);
	if (input != 1 && input != 2 && input != 3) {
		printf("无效的输入！！！");
		return 0;
	}
	return input;
}
int get_robot_move() {
	return (rand() % (SCISSORS - ROCK + 1)) + ROCK;
}
void determine_winner(uint32_t input, uint32_t robot_input) {
	int arr[4] = { 0,PAPER,SCISSORS,ROCK};
	if (input == arr[robot_input]) {
