### 142. 企业使用迭代方法来替代递归
```c
#include <stdio.h>
#include <stdint.h>
#include <inttypes.h>

int flib(uint32_t n);

//斐波那契数列
int main(void) {
	printf("%"PRIu32, flib(4));
	return 0;
}
//1,1,2,3,5,8
int flib(uint32_t n) {
	if (n <= 1) {
		return n;
	}
	uint32_t flib_0 = 0;
	uint32_t flib_1 = 1;
	uint32_t flib_n;

	for (uint32_t i = 2; i <= n; ++i) { 
	//++i：c中没有太大性能区别(理论上++i性能更好)
		flib_n = flib_0 + flib_1;
		flib_0 = flib_1;
		flib_1 = flib_n;
	}
	return flib_n;
}
```
