#### xxtea
XXTEA，又称Corrected Block TEA，是XTEA的升级版 ，设计者是Roger Needham, David Wheeler。其实现过程要比前两种的算法略显复杂些，加密的明文不再是64bit（两个32位无符号整数），并且其加密轮数是由**n**，即待加密数据个数决定的。
>特点：原字符串长度可以不是4的倍数了
```c
#include <stdio.h>
#include <stdint.h>
#define DELTA 0x9e3779b9
#define MX (((z>>5^y<<2) + (y>>3^z<<4)) ^ ((sum^y) + (key[(p&3)^e] ^ z)))

void btea(uint32_t *v, int n, uint32_t const key[4])
{
    uint32_t y, z, sum;
    unsigned p, rounds, e;
    if (n > 1)            /* Coding Part */
    {
        rounds = 6 + 52/n;
        sum = 0;
        z = v[n-1];
        do
        {
            sum += DELTA;
            e = (sum >> 2) & 3;
            for (p=0; p<n-1; p++)
            {
                y = v[p+1];
                z = v[p] += MX;
            }
            y = v[0];
            z = v[n-1] += MX;
        }
        while (--rounds);
    }
    else if (n < -1)      /* Decoding Part */
    {
        n = -n;
        rounds = 6 + 52/n;
        sum = rounds*DELTA;
        y = v[0];
        do
        {
            e = (sum >> 2) & 3;
            for (p=n-1; p>0; p--)
            {
                z = v[p-1];
                y = v[p] -= MX;
            }
            z = v[n-1];
            y = v[0] -= MX;
            sum -= DELTA;
        }
        while (--rounds);
    }
}


int main()
{
    uint32_t v[2]= {1,2};
    uint32_t const k[4]= {2,2,3,4};
    int n= 2; //n的绝对值表示v的长度，取正表示加密，取负表示解密
    // v为要加密的数据是两个32位无符号整数
    // k为加密解密密钥，为4个32位无符号整数，即密钥长度为128位
    printf("加密前原始数据：%u %u\n",v[0],v[1]);
    btea(v, n, k);
    printf("加密后的数据：%u %u\n",v[0],v[1]);
    btea(v, -n, k);
    printf("解密后的数据：%u %u\n",v[0],v[1]);
    return 0;
}
```
- 字符串密匙
```c
#include <stdio.h>
#include <stdint.h>

#define DELTA 0x9E3779B9
#define MX (((z>>5 ^ y<<2) + (y>>3 ^ z<<4)) ^ ((sum^y) + (key[(p&3)^e] ^ z)))

void btea(uint32_t* v, int n, const uint32_t key[4])
{
    uint32_t y, z, sum;
    unsigned p, rounds, e;

    if (n < -1)      /* Decoding Part */
    {
        n = -n;
        rounds = 6 + 52 / n;
        sum = rounds * DELTA;
        y = v[0];
        do
        {
            e = (sum >> 2) & 3;
            for (p = n - 1; p > 0; p--)
            {
                z = v[p - 1];
                y = v[p] -= MX;
            }
            z = v[n - 1];
            y = v[0] -= MX;
            sum -= DELTA;
        } while (--rounds);
    }
}

int main() {
    uint32_t v[12] = { 0x8c12d3dfUL, 0x5f4c4137UL, 0x1a9d3d02UL, 0x2d1294b7UL, 0xfb622b37UL, 0xd18d84e3UL, 0x64c4592UL, 0x16985cabUL, 0xfdb06d69UL, 0xfb30b1e3UL, 0x925c2fd3UL, 0x2e1bb40cUL };

    const uint32_t* k = (const uint32_t*)"keykeykey";

    btea(v, -12, k);

    printf("%s\n", (char*)v);
    return 0;
}
```

XXTEA算法的解密同样只是对加密算法的数据处理顺序进行倒置，同时加法改减法（减法改加法）。

**识别特征：**

*   轮数一般为 rounds = 6 + 52 / n，比较明显，一般很少改动

#### 总结

xxtea算法的例题很少见，感觉见的最多的是xtea及其变形。每一道题都有不同，不能死套着脚本，应该根据题的不同而进行修改，比如轮数，魔数，异或等的一些改变。

**识别特征：**

*   可能存在针对64bit以及128bit数字的操作（输入的msg和key）

*   存在**先进行位移，然后异或**的类似操作（`(z>>5^y<<2)`这类混合变换）

*   前面一个复杂的混合变换的结果可能会叠加到另一个值上，两者相互叠加（Feistel 结构）

*   获取密钥的时候，会使用某一个常量值作为下标（`key[(sum>>11) & 3]`）

*   会在算法开始定义一个delta，并且这个值不断的参与算法，但是**从来不会受到输入的影响**（delta数值，根据见过的题目中很少会直接使用0x9e3779b9）

