```python
flag = ''
Str = 'ylqq]aycqyp{'
for i in Str:
    # 假设它来自普通分支 (加密是 -2，所以解密是 +2)
    p1 = ord(i) + 2
    # 假设它来自特殊分支 (加密是 +24，所以解密是 -24)
    p2 = ord(i) - 24

    # 验证假设：如果 p1 是普通字符，那假设1成立
    if (p1 <= 96 or p1 > 98) and (p1 <= 64 or p1 > 66):
        flag += chr(p1)
    # 否则，如果 p2 是特殊字符 (a,b,A,B)，那假设2成立
    else:
        flag += chr(p2)
print(flag) # 输出: {nss_c{es{r}
```
