@Override
public void onClick(View v) {
    // 检查点击的是否是校验按钮 (buttonFirst)
    if (v == this.binding.contentMain.frist.buttonFirst) {
        // 1. 获取输入框中的文本
        String tx = String.valueOf(this.binding.contentMain.frist.text.getText());

        // 2. 空值检查
