  padding:0;
  background-color:var(--dropdown-btn-bg-color);
  border:var(--dropdown-btn-border);
  border-radius:2px;
  color:var(--main-color);
  font-size:12px;
  line-height:14px;
  -webkit-user-select:none;
     -moz-user-select:none;
          user-select:none;
  cursor:default;
  box-sizing:border-box;
  outline:none;
}

.dropdownToolbarButton:hover{
    background-color:var(--button-hover-color);
  }

.dropdownToolbarButton  > select{
    -webkit-appearance:none;
       -moz-appearance:none;
            appearance:none;
    width:inherit;
    min-width:inherit;
    height:28px;
    font:message-box;
    font-size:12px;
    color:var(--main-color);
    margin:0;
    padding-block:1px 2px;
    padding-inline:6px 38px;
    border:none;
    outline:none;
    background-color:var(--dropdown-btn-bg-color);
  }

:is(.dropdownToolbarButton > select)  > option{
      background:var(--doorhanger-bg-color);
      color:var(--main-color);
    }

:is(.dropdownToolbarButton > select):is(:hover,:focus-visible){
      background-color:var(--button-hover-color);
      color:var(--toggled-btn-color);
    }

.dropdownToolbarButton::after{
    position:absolute;
    display:inline;
    width:var(--icon-size);
    height:var(--icon-size);

    content:"";
    background-color:var(--toolbar-icon-bg-color);
    -webkit-mask-size:cover;
            mask-size:cover;

    inset-inline-end:4px;
    pointer-events:none;
    -webkit-mask-image:var(--toolbarButton-menuArrow-icon);
            mask-image:var(--toolbarButton-menuArrow-icon);
  }

.dropdownToolbarButton:is(:hover,:focus-visible,:active)::after{
    background-color:var(--toolbar-icon-hover-bg-color);
  }

#toolbarContainer{
  --menuitem-height:calc(var(--toolbar-height) - 6px);

  width:100%;
  height:var(--toolbar-height);
  padding:var(--toolbar-vertical-padding) var(--toolbar-horizontal-padding);
  position:relative;
  box-sizing:border-box;
  font:message-box;
  background-color:var(--toolbar-bg-color);
  box-shadow:var(--toolbar-box-shadow);
  border-bottom:var(--toolbar-border-bottom);
}

#toolbarContainer #toolbarViewer{
    width:100%;
    height:100%;
    justify-content:space-between;
  }

:is(#toolbarContainer #toolbarViewer)  > *{
      flex:none;
    }

:is(#toolbarContainer #toolbarViewer) input{
      font:message-box;
    }

:is(#toolbarContainer #toolbarViewer) .toolbarButtonSpacer{
      width:30px;
      display:block;
      height:1px;
    }

:is(#toolbarContainer #toolbarViewer) #toolbarViewerLeft #numPages.toolbarLabel{
      padding-inline-start:3px;
      flex:none;
    }

#toolbarContainer #loadingBar{
    --progressBar-percent:0%;
    --progressBar-end-offset:0;

    position:absolute;
    top:var(--toolbar-height);
    inset-inline:0 var(--progressBar-end-offset);
    height:4px;
    background-color:var(--progressBar-bg-color);
    border-bottom:1px solid var(--toolbar-border-color);
    transition-property:inset-inline-start;
    transition-duration:var(--sidebar-transition-duration);
    transition-timing-function:var(--sidebar-transition-timing-function);
  }

:is(#toolbarContainer #loadingBar) .progress{
      position:absolute;
      top:0;
      inset-inline-start:0;
      width:100%;
      transform:scaleX(var(--progressBar-percent));
      transform-origin:calc(50% - 50% * var(--dir-factor)) 0;
      height:100%;
      background-color:var(--progressBar-color);
      overflow:hidden;
      transition:transform 200ms;
    }

.indeterminate:is(#toolbarContainer #loadingBar) .progress{
      transform:none;
      background-color:var(--progressBar-bg-color);
      transition:none;
    }

:is(.indeterminate:is(#toolbarContainer #loadingBar) .progress) .glimmer{
        position:absolute;
        top:0;
        inset-inline-start:0;
        height:100%;
        width:calc(100% + 150px);
        background:repeating-linear-gradient(
          135deg,
          var(--progressBar-blend-color) 0,
          var(--progressBar-bg-color) 5px,
          var(--progressBar-bg-color) 45px,
          var(--progressBar-color) 55px,
          var(--progressBar-color) 95px,
          var(--progressBar-blend-color) 100px
        );
        animation:progressIndeterminate 1s linear infinite;
      }

@media all and (max-width: 840px){
  #sidebarContainer{
    background-color:var(--sidebar-narrow-bg-color);
  }
  #outerContainer.viewsManagerOpen #viewerContainer{
    inset-inline-start:0 !important;
  }
}

@media all and (max-width: 750px){
  #outerContainer .hiddenMediumView{
    display:none !important;
  }
  #outerContainer .visibleMediumView:not(.hidden, [hidden]){
    display:inline-block !important;
  }
}

@media all and (max-width: 690px){
  .hiddenSmallView,
  .hiddenSmallView *{
    display:none !important;
  }

  #toolbarContainer #toolbarViewer .toolbarButtonSpacer{
    width:0;
  }
}

@media all and (max-width: 560px){
  #scaleSelectContainer{
    display:none;
  }
}

